"""Tests for the scoring function.

The scaffold ships with a stub that returns 0.0. These tests serve two purposes:

1. **Contract tests** — assert the shape and types that the pipeline requires.
   These pass regardless of implementation.
2. **Stub detection** — assert that real scoring produces non-zero values for
   known inputs. These FAIL against the stub, signalling that scoring must be
   implemented before deploy. Mark them xfail until real scoring is written.
"""

from __future__ import annotations

import pytest
from starter_challenge.scoring import score_prediction


class TestScoringContract:
    """Shape/type requirements — must pass for ANY valid implementation."""

    def test_returns_dict(self):
        result = score_prediction({"value": 0.5}, {"profit": 0.01})
        assert isinstance(result, dict)

    def test_has_value_key(self):
        result = score_prediction({"value": 0.5}, {"profit": 0.01})
        assert "value" in result
        assert isinstance(result["value"], (int, float))

    def test_has_success_key(self):
        result = score_prediction({"value": 0.5}, {"profit": 0.01})
        assert "success" in result
        assert isinstance(result["success"], bool)

    def test_has_failed_reason_key(self):
        result = score_prediction({"value": 0.5}, {"profit": 0.01})
        assert "failed_reason" in result
        assert result["failed_reason"] is None or isinstance(
            result["failed_reason"], str
        )


class TestScoringBehavior:
    """Behavioral expectations — these MUST fail against the 0.0 stub.

    When you implement real scoring, remove the xfail markers.
    If these pass with the stub, the test is wrong.
    """

    @pytest.mark.xfail(
        reason="Stub returns 0.0 — implement real scoring in scoring.py",
        strict=True,
    )
    def test_correct_prediction_scores_positive(self):
        """A prediction in the right direction should score > 0."""
        # Bullish prediction, price went up
        result = score_prediction(
            {"value": 0.5}, {"profit": 0.02, "direction_up": True}
        )
        assert result["value"] > 0, (
            "Correct directional prediction should score positive"
        )

    @pytest.mark.xfail(
        reason="Stub returns 0.0 — implement real scoring in scoring.py",
        strict=True,
    )
    def test_wrong_prediction_scores_negative(self):
        """A prediction in the wrong direction should score < 0."""
        # Bullish prediction, price went down
        result = score_prediction(
            {"value": 0.5}, {"profit": -0.02, "direction_up": False}
        )
        assert result["value"] < 0, "Wrong directional prediction should score negative"

    @pytest.mark.xfail(
        reason="Stub returns 0.0 — implement real scoring in scoring.py",
        strict=True,
    )
    def test_different_inputs_produce_different_scores(self):
        """Scoring must differentiate between predictions."""
        good = score_prediction({"value": 0.8}, {"profit": 0.05, "direction_up": True})
        bad = score_prediction({"value": 0.8}, {"profit": -0.05, "direction_up": False})
        assert good["value"] != bad["value"], (
            "Different ground truths should produce different scores"
        )

"""Tests for the example tracker models."""

from __future__ import annotations

import pytest
from starter_challenge.examples.mean_reversion_tracker import MeanReversionTracker
from starter_challenge.examples.trend_following_tracker import TrendFollowingTracker
from starter_challenge.examples.volatility_regime_tracker import VolatilityRegimeTracker


def _make_candles(closes: list[float], base_ts: int = 1700000000) -> list[dict]:
    return [
        {
            "ts": base_ts + i * 60,
            "open": c,
            "high": c + 5,
            "low": c - 5,
            "close": c,
            "volume": 100,
        }
        for i, c in enumerate(closes)
    ]


def _make_tick(subject: str, closes: list[float]) -> dict:
    return {
        "symbol": subject,
        "asof_ts": 1700000000 + len(closes) * 60,
        "candles_1m": _make_candles(closes),
    }


UPTREND_CLOSES = [40000 + i * 50 for i in range(10)]
DOWNTREND_CLOSES = [40000 - i * 50 for i in range(10)]
EMPTY_TICK = {"symbol": "BTC", "asof_ts": 0, "candles_1m": []}


@pytest.fixture(
    params=[
        MeanReversionTracker,
        TrendFollowingTracker,
        VolatilityRegimeTracker,
    ]
)
def tracker(request):
    """Parametrize over all example trackers."""
    return request.param()


class TestExampleContract:
    """Every example must satisfy the model contract."""

    def test_returns_dict_with_value(self, tracker):
        tracker.tick(_make_tick("BTC", UPTREND_CLOSES))
        result = tracker.predict("BTC", resolve_horizon_seconds=60, step_seconds=15)
        assert isinstance(result, dict)
        assert "value" in result
        assert isinstance(result["value"], (int, float))

    def test_empty_data_returns_zero(self, tracker):
        tracker.tick(EMPTY_TICK)
        result = tracker.predict("BTC", resolve_horizon_seconds=60, step_seconds=15)
        assert result["value"] == 0.0

    def test_no_tick_returns_zero(self, tracker):
        result = tracker.predict("BTC", resolve_horizon_seconds=60, step_seconds=15)
        assert result["value"] == 0.0

    def test_sparse_candles_does_not_crash(self, tracker):
        """Fewer than 3 candles — models should handle gracefully."""
        tracker.tick(_make_tick("BTC", [40000, 40010]))
        result = tracker.predict("BTC", resolve_horizon_seconds=60, step_seconds=15)
        assert isinstance(result["value"], (int, float))
        assert result["value"] == 0.0  # < 3 prices triggers early return

    def test_single_candle(self, tracker):
        tracker.tick(_make_tick("BTC", [40000]))
        result = tracker.predict("BTC", resolve_horizon_seconds=60, step_seconds=15)
        assert result["value"] == 0.0


class TestMultiSubjectIsolation:
    """tick() data must be isolated per subject (P0 bug #1 regression test)."""

    def test_btc_and_eth_produce_different_predictions(self, tracker):
        tracker.tick(_make_tick("BTC", UPTREND_CLOSES))
        tracker.tick(_make_tick("ETH", DOWNTREND_CLOSES))

        btc_pred = tracker.predict("BTC", 60, 15)
        eth_pred = tracker.predict("ETH", 60, 15)

        assert btc_pred["value"] != eth_pred["value"], (
            f"BTC and ETH predictions should differ but both are {btc_pred['value']}"
        )

    def test_ticking_eth_does_not_change_btc(self, tracker):
        tracker.tick(_make_tick("BTC", UPTREND_CLOSES))
        btc_before = tracker.predict("BTC", 60, 15)["value"]

        tracker.tick(_make_tick("ETH", DOWNTREND_CLOSES))
        btc_after = tracker.predict("BTC", 60, 15)["value"]

        assert btc_before == btc_after

    def test_unknown_subject_returns_zero(self, tracker):
        tracker.tick(_make_tick("BTC", UPTREND_CLOSES))
        result = tracker.predict("SOL", 60, 15)
        assert result["value"] == 0.0

from __future__ import annotations

from starter_challenge.tracker import TrackerBase


class MeanReversionTracker(TrackerBase):
    """Predicts pullback after short-term overextension."""

    def predict(
        self, subject: str, resolve_horizon_seconds: int, step_seconds: int
    ) -> dict:
        prices = _extract_prices(self._get_data(subject))
        if len(prices) < 3:
            return {"value": 0.0}

        lookback = min(5, len(prices))
        window = prices[-lookback:]
        average = sum(window) / lookback
        deviation = (window[-1] - average) / max(abs(average), 1e-9)

        return {"value": -0.7 * deviation}


def _extract_prices(latest_data):
    if isinstance(latest_data, dict) and isinstance(
        latest_data.get("candles_1m"), list
    ):
        return _closes(latest_data["candles_1m"])
    return []


def _closes(candles):
    closes = []
    for row in candles:
        if not isinstance(row, dict):
            continue
        value = row.get("close")
        try:
            closes.append(float(value))
        except Exception:
            continue
    return closes

