class TestScoringBehavior:
    """Behavioral expectations for MAPE-based property price scoring."""

    def test_perfect_prediction_scores_one(self):
        """Exact match should score 1.0 (MAPE = 0)."""
        result = score_prediction(
            {"predicted_price": 500000.0}, {"price": 500000.0}
        )
        assert result["value"] == 1.0
        assert result["mape"] == 0.0
        assert result["mae"] == 0.0

    def test_close_prediction_scores_high(self):
        """10% off should score ~0.9."""
        result = score_prediction(
            {"predicted_price": 550000.0}, {"price": 500000.0}
        )
        assert 0.85 < result["value"] < 0.95
        assert abs(result["mape"] - 0.1) < 0.01
        assert result["mae"] == 50000.0

    def test_far_off_prediction_scores_low(self):
        """100% off should score 0.0."""
        result = score_prediction(
            {"predicted_price": 1000000.0}, {"price": 500000.0}
        )
        assert result["value"] == 0.0
        assert result["mape"] >= 1.0

    def test_different_predictions_produce_different_scores(self):
        """Scoring must differentiate between predictions."""
        good = score_prediction(
            {"predicted_price": 510000.0}, {"price": 500000.0}
        )
        bad = score_prediction(
            {"predicted_price": 700000.0}, {"price": 500000.0}
        )
        assert good["value"] > bad["value"]

    def test_score_never_negative(self):
        """Score should be clamped to 0.0 minimum."""
        result = score_prediction(
            {"predicted_price": 5000000.0}, {"price": 100000.0}
        )
        assert result["value"] >= 0.0

    def test_zero_actual_price_does_not_crash(self):
        """Edge case: ground truth price is zero."""
        result = score_prediction(
            {"predicted_price": 100000.0}, {"price": 0.0}
        )
        assert isinstance(result["value"], float)
        assert result["success"] is True

    def test_sqft_model_vs_median_model(self):
        """SqftPriceTracker should outscore MedianPriceTracker on a $400k/2000sqft house."""
        # 2000 sqft * $200 = $400,000 (exact), median = $350,000
        sqft_result = score_prediction(
            {"predicted_price": 400000.0}, {"price": 400000.0}
        )
        median_result = score_prediction(
            {"predicted_price": 350000.0}, {"price": 400000.0}
        )
        assert sqft_result["value"] > median_result["value"]

