def _encode_predict(self, scope: dict[str, Any]) -> tuple:
    """Encode arguments according to ``contract.call_method.args``.

    Each arg reads its value from the scope dict (falling back to the
    contract's default scope), converts to the declared type, and is
    packed as a proto Argument when the model-runner client is available.
    """
    call_args = self.contract.call_method.args
    scope_defaults = self.contract.scope.model_dump()

    # Resolve raw values
    raw_values: list[tuple[str, Any]] = []
    for arg in call_args:
        value = scope.get(arg.name)
        if value is None:
            value = scope_defaults.get(arg.name, "")
        # Coerce to declared type
        utype = arg.type.upper()
        if utype == "INT":
            value = int(value)
        elif utype == "FLOAT":
            value = float(value)
        elif utype == "STRING":
            value = str(value)
        # JSON left as-is
        raw_values.append((utype, value))

    if MODEL_RUNNER_PROTO_AVAILABLE:
        arguments = []
        for position, (utype, value) in enumerate(raw_values, start=1):
            vtype = self._get_variant_type(utype)
            arguments.append(
                Argument(
                    position=position,
                    data=Variant(type=vtype, value=encode_data(vtype, value)),
                )
            )
        return (arguments, [])

    return tuple(v for _, v in raw_values)

class RealtimePredictService(PredictService):
    def __init__(
        self, checkpoint_interval_seconds: int = 60 * 60, **kwargs: Any
    ) -> None:
        super().__init__(**kwargs)
        self.checkpoint_interval_seconds = checkpoint_interval_seconds
        self._next_run: dict[str, datetime] = {}

    @staticmethod
    def validate_prediction_configs(
        configs: list[dict[str, Any]],
        feed_poll_seconds: float,
    ) -> None:
        """Validate prediction configs against feed timing constraints.

        Raises ValueError if any active config has resolve_horizon_seconds
        that is too low to accumulate feed data for ground truth resolution.
        resolve_horizon_seconds=0 is valid (immediate resolution, e.g. live trading).
        Must be called at startup to fail fast.
        """
        for config in configs:
            if not config.get("active", True):
                continue

            schedule = config.get("schedule") or {}
            resolve_horizon = schedule.get("resolve_horizon_seconds", 0)
            scope_key = config.get("scope_key", "<unknown>")

            # 0 means immediate resolution (live trading) — skip feed timing check
            if resolve_horizon == 0:
                continue

            if resolve_horizon < feed_poll_seconds:
                raise ValueError(
                    f"Config '{scope_key}': resolve_horizon_seconds={resolve_horizon} "
                    f"is less than feed_poll_seconds={feed_poll_seconds}. "
                    f"Predictions will never accumulate enough feed data to "
                    f"resolve ground truth. All scores will be 0. "
                    f"Set resolve_horizon_seconds >= {feed_poll_seconds} "
                    f"or use 0 for immediate resolution (live trading)."
                )

    # ── main loop ──

    async def run(self) -> None:
        self.logger.info("realtime predict service started")
        while not self.stop_event.is_set():
            try:
                await self.run_once()
            except asyncio.CancelledError:
                raise
            except Exception as exc:
                self.logger.exception("predict loop error: %s", exc)
            await self._wait_for_data()

    async def run_once(
        self, raw_input: dict[str, Any] | None = None, now: datetime | None = None
    ) -> bool:
        now = now or datetime.now(UTC)
        await self.init_runner()

        # 1. get data → tick models
        if raw_input is not None:
            validated = self.contract.raw_input_type.model_validate(raw_input)
            data = validated.model_dump()
            inp = InputRecord(
                id=f"INP_{now.strftime('%Y%m%d_%H%M%S.%f')[:-3]}",
                raw_data=data,
                received_at=now,
            )
        else:
            inp = self.get_data(now)
        await self._tick_models(inp.raw_data)

        # 2. run configs → build records → save
        predictions = await self._predict_a
